ls.content:
let dir = arguments[1];
if(dir == undefined) dir = workingdir;
let files = readdir(dir);
if(files.length == 0){
	log("empty dir");
	return;
};
let str = "";
for(let i = 0; i<files.length; i++){
	str += files[i] + " ";
};
log(str);

cd.content:
if(arguments.length > 2) log("too many arguments");

if(arguments[1] == undefined){
	workingdir = "/home"
	return;
}

if(arguments[1] == ".."){
	let frag = workingdir.split("/");
	frag = frag.slice(0, frag.length-2);
	workingdir = frag.join("/");
	return;
};

if(getfile(arguments[1]) == undefined){
	log("no such dir");
	return;
} else {
	if(getfile(arguments[1]).type != 1){
		log("path isnt a dir");
		return;
	} else {
		workingdir = arguments[1];
		return;
	};
}

cat.content:
let f = read(arguments[1]);
if(f == -1){
	log("file doesnt exist");
	return;
}

if(f == -2){
	log("file is a dir");
	return;
}

log(f);

touch.content:
if(arguments[1] == undefined){
	log("no name provided");
	return;
}
create(arguments[1])

mkdir.content:
if(arguments[1] == undefined){
	log("no name provided");
	return;
}

create(arguments[1], 1);

